export interface ExtractedData {
  data: Record<string, number>;
  periodo: string;
  tipo: string;
  identificacion: string;
  razonSocial: string;
}

/**
 * Normaliza y convierte un string de valor monetario a un número de forma robusta,
 * manejando diversos formatos con '.' y ',' como separadores.
 * @param valueStr El string a limpiar.
 * @returns El valor numérico, o 0 si no es válido.
 */
function cleanAndParseValue(valueStr: string): number {
  // 1. Limpiar el string de espacios en blanco
  const s = String(valueStr).trim().replace(/\s/g, '');
  if (s === '') return 0;

  const commaCount = (s.match(/,/g) || []).length;
  const periodCount = (s.match(/\./g) || []).length;
  let numberString: string;

  // 2. Casos con solo comas
  if (commaCount > 0 && periodCount === 0) {
    const parts = s.split(',');
    // Heurística: si la última parte tiene 3 dígitos y hay más de una parte,
    // es probable que sea un separador de miles (ej: 1,000).
    // De lo contrario, es un separador decimal (ej: 1,23).
    if (parts.length > 1 && parts[parts.length - 1].length === 3) {
      numberString = s.replace(/,/g, '');
    } else {
      numberString = s.replace(',', '.');
    }
  }
  // 3. Casos con solo puntos
  else if (periodCount > 0 && commaCount === 0) {
    const parts = s.split('.');
    // Heurística: Si hay más de un punto, son separadores de miles (1.234.567).
    // O, si hay un solo punto y la parte DESPUÉS tiene 3 dígitos, es probable
    // que sea un separador de miles (ej: 1.234, 12.345, 123.456).
    // Esto distingue "1.234" (mil) de "1234.56" (decimal).
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3)) {
       numberString = s.replace(/\./g, '');
    } else {
      // De lo contrario, se trata como un decimal (123.45, 1234.56)
      numberString = s;
    }
  }
  // 4. Casos con ambos separadores
  else if (commaCount > 0 && periodCount > 0) {
    // El último separador que aparece es el decimal
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) {
      // Formato: 1.234,56 -> "1234.56"
      numberString = s.replace(/\./g, '').replace(',', '.');
    } else {
      // Formato: 1,234.56 -> "1234.56"
      numberString = s.replace(/,/g, '');
    }
  }
  // 5. Sin separadores
  else {
    numberString = s;
  }

  const result = parseFloat(numberString);
  return isNaN(result) ? 0 : result;
}


/**
 * Extrae datos de un formulario de impuestos usando reglas y expresiones regulares.
 * @param text El texto completo extraído de un archivo PDF.
 * @returns Una promesa que resuelve a un objeto con los datos extraídos.
 */
export async function extractDataWithRules(text: string): Promise<ExtractedData> {
  return new Promise((resolve) => {
    const dataMap: Record<string, number> = {};

    // Expresión regular para encontrar casilleros (3 o 4 dígitos) y sus valores.
    // MODIFICADO: (\d{3,4}) para aceptar casilleros como 3120, 3620, etc.
    const lines = text.split('\n');
    const casilleroValueRegex = /(\d{3,4})\s+(-?[\d.,]+)/g;

    for (const line of lines) {
        // Busca pares directos de casillero-valor en una línea
        let match;
        while ((match = casilleroValueRegex.exec(line)) !== null) {
            const id = match[1];
            const valueStr = match[2];
            const value = cleanAndParseValue(valueStr);

            if (!isNaN(value) && value !== 0) {
                 // Evita sobrescribir valores ya encontrados, asumiendo que el primero es el correcto
                if (!dataMap[id]) {
                    dataMap[id] = value;
                }
            }
        }
    }

    // Regex para encontrar el período fiscal
    const periodoRegex = /(ENERO|FEBRERO|MARZO|ABRIL|MAYO|JUNIO|JULIO|AGOSTO|SEPTIEMBRE|OCTUBRE|NOVIEMBRE|DICIEMBRE)\s+(\d{4})|(PRIMER|SEGUNDO)\s+SEMESTRE\s+(\d{4})/i;
    const periodoMatch = text.match(periodoRegex);
    const periodo = periodoMatch ? periodoMatch[0].toUpperCase() : '';

    // Regex para encontrar el tipo de declaración
    const tipoRegex = /(ORIGINAL|SUSTITUTIVA)/i;
    const tipoMatch = text.match(tipoRegex);
    const tipo = tipoMatch ? tipoMatch[0].toUpperCase() : '';

    // Regex to find Identification (RUC)
    const identificacionRegex = /(?:IDENTIFICACIÓN(?: DEL SUJETO PASIVO)?|RUC)\s*(\d{13})/i;
    const identificacionMatch = text.match(identificacionRegex);
    const identificacion = identificacionMatch ? identificacionMatch[1] : '';

    // Regex to find Razón Social (Business Name)
    const razonSocialRegex = /(?:RAZÓN SOCIAL(?: O APELLIDOS Y NOMBRES COMPLETOS)?)\s+([A-ZÑ\sÁÉÍÓÚÜ]+?)(?:\s+\d{3}|$|\n)/i;
    const razonSocialMatch = text.match(razonSocialRegex);
    const razonSocial = razonSocialMatch ? razonSocialMatch[1].trim() : '';

    resolve({
      data: dataMap,
      periodo,
      tipo,
      identificacion,
      razonSocial,
    });
  });
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { withholdingStructure, WithholdingRow } from '../data/withholdingStructure';
import { parsePdfText } from '../services/pdfParser';
import { extractDataWithRules } from '../services/ruleBasedParser';
import { UploadIcon, LoaderIcon, AlertTriangleIcon, ClipboardListIcon, FileTextIcon, FileSpreadsheetIcon, DownloadIcon, ChevronDownIcon, TrashIcon } from './icons';

// Access globals via window
const getJsPDF = () => (window as any).jspdf;
const getXLSX = () => (window as any).XLSX;

interface MonthlyData {
    month: string;
    year: string;
    fileName: string;
    data: Record<string, number>;
    identificacion?: string;
    razonSocial?: string;
}

const MONTHS_ORDER = ['ENERO', 'FEBRERO', 'MARZO', 'ABRIL', 'MAYO', 'JUNIO', 'JULIO', 'AGOSTO', 'SEPTIEMBRE', 'OCTUBRE', 'NOVIEMBRE', 'DICIEMBRE'];

const WithholdingForm: React.FC = () => {
    const [monthlyData, setMonthlyData] = useState<MonthlyData[]>([]);
    const [activeMonthTab, setActiveMonthTab] = useState<string>('');
    const [isProcessing, setIsProcessing] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [isExportMenuOpen, setIsExportMenuOpen] = useState(false);
    const [ruc, setRuc] = useState<string>('');
    const [razonSocial, setRazonSocial] = useState<string>('');

    const exportMenuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
                setIsExportMenuOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, []);

    const sortedMonths = useMemo(() => {
        return [...new Set<string>(monthlyData.map(d => d.month))]
            .sort((a, b) => MONTHS_ORDER.indexOf(a) - MONTHS_ORDER.indexOf(b));
    }, [monthlyData]);

    const totalData = useMemo(() => {
        const totals: Record<string, number> = {};
        monthlyData.forEach(month => {
            for (const key in month.data) {
                totals[key] = (totals[key] || 0) + month.data[key];
            }
        });
        // Round final totals
        for (const key in totals) {
            totals[key] = parseFloat(totals[key].toFixed(2));
        }
        return totals;
    }, [monthlyData]);

    const handleClearData = () => {
        if (window.confirm("¿Está seguro que desea borrar todos los datos cargados?")) {
            setMonthlyData([]);
            setActiveMonthTab('');
            setRuc('');
            setRazonSocial('');
            setError(null);
        }
    };

    const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const files = event.target.files;
        if (!files || files.length === 0) return;

        setIsProcessing(true);
        setError(null);
        setMonthlyData([]); 

        const processFile = async (file: File): Promise<MonthlyData | null> => {
            try {
                const text = await parsePdfText(file);
                const extracted = await extractDataWithRules(text);
                if (!extracted.periodo) {
                    console.warn(`Could not determine period for file: ${file.name}`);
                    return null;
                }
                const [month, year] = extracted.periodo.split(' ');
                return { 
                    month, 
                    year, 
                    fileName: file.name, 
                    data: extracted.data,
                    identificacion: extracted.identificacion,
                    razonSocial: extracted.razonSocial
                };
            } catch (err) {
                console.error(`Failed to process ${file.name}:`, err);
                return null;
            }
        };

        try {
            const results = await Promise.all(Array.from(files).map(processFile));
            const validData = results.filter((d): d is MonthlyData => d !== null);

            if (validData.length === 0 && files.length > 0) {
                 throw new Error("No se pudo extraer datos válidos de ninguno de los archivos. Verifique que sean declaraciones.");
            }

            const foundRuc = validData.find(d => d.identificacion)?.identificacion;
            const foundName = validData.find(d => d.razonSocial)?.razonSocial;

            if (foundRuc && !ruc) setRuc(foundRuc);
            if (foundName && !razonSocial) setRazonSocial(foundName);

            validData.sort((a, b) => MONTHS_ORDER.indexOf(a.month) - MONTHS_ORDER.indexOf(b.month));
            setMonthlyData(validData);
            setActiveMonthTab('TOTAL'); 
        } catch (err) {
            if (err instanceof Error) setError(err.message);
            else setError("Ocurrió un error desconocido al procesar los archivos.");
        } finally {
            setIsProcessing(false);
            event.target.value = '';
        }
    };

    const formatNumber = (num: number) => {
        return num.toLocaleString('es-EC', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    };

    const dataToDisplay = useMemo(() => {
        if (activeMonthTab === 'TOTAL') {
            return totalData;
        }
        return monthlyData.find(d => d.month === activeMonthTab)?.data || {};
    }, [activeMonthTab, monthlyData, totalData]);

    const handleExportPdf = () => {
        setIsExportMenuOpen(false);
        const jspdf = getJsPDF();
        if (!jspdf) {
            setError("La librería jsPDF no está cargada.");
            return;
        }
        const { jsPDF } = jspdf;
        const doc = new jsPDF({ orientation: 'landscape' });
        const year = monthlyData.length > 0 ? monthlyData[0].year : new Date().getFullYear();
        const fileName = `reporte_retenciones_${year}.pdf`;

        doc.setFontSize(18);
        doc.setTextColor(0, 51, 102); 
        doc.text(`Reporte Anual de Retenciones en la Fuente`, 14, 20);

        doc.setFontSize(11);
        doc.setTextColor(50);

        let headerY = 28;
        if (ruc) {
            doc.text(`RUC: ${ruc}`, 14, headerY);
            headerY += 6;
        }
        if (razonSocial) {
            doc.text(`Razón Social: ${razonSocial}`, 14, headerY);
            headerY += 6;
        }

        doc.setTextColor(100);
        doc.text(`Período Fiscal: ${year}`, 14, headerY);

        let finalY = headerY + 10;

        const tableBody: (string | number)[][] = [];

        withholdingStructure.forEach(row => {
            if (row.isTitle) {
                 // Skip titles for body rows, they are headers in UI but we might handle them differently in PDF or just skip
                 // We'll add them as bold rows without values
                 tableBody.push([row.description, '', '', '', '']);
                 return;
            }

            const baseField = row.baseField;
            const retField = row.retentionField;

            const valBase = baseField ? (dataToDisplay[baseField.id] || 0) : 0;
            const valRet = retField ? (dataToDisplay[retField.id] || 0) : 0;

            if (valBase > 0 || valRet > 0) {
                tableBody.push([
                    row.description,
                    baseField?.id || '',
                    valBase === 0 ? '-' : formatNumber(valBase),
                    retField?.id || '',
                    valRet === 0 ? '-' : formatNumber(valRet)
                ]);
            }
        });

        if (tableBody.length > 0) {
            const tableHeaders = ['Descripción', 'Cas. Base', 'Base Imponible', 'Cas. Ret', 'Valor Retenido'];

            doc.autoTable({
                startY: finalY,
                head: [[
                    { content: "RESUMEN DE RETENCIONES", colSpan: 5, styles: { halign: 'center', fillColor: [0, 51, 102] } }
                ], tableHeaders],
                body: tableBody,
                theme: 'grid',
                styles: { fontSize: 8, cellPadding: 1, lineColor: [0,0,0], lineWidth: 0.1 },
                headStyles: { fontStyle: 'bold', halign: 'center', fillColor: [22, 160, 233], lineColor: [0,0,0], lineWidth: 0.1 },
                columnStyles: {
                    0: { cellWidth: 'auto' },
                    1: { halign: 'center', cellWidth: 10, fontStyle: 'bold' },
                    2: { halign: 'right', cellWidth: 25 },
                    3: { halign: 'center', cellWidth: 10, fontStyle: 'bold' },
                    4: { halign: 'right', cellWidth: 25 },
                },
                didParseCell: function(data: any) {
                    // Check if it's a title row (empty codes and values)
                    if (data.section === 'body' && data.row.raw[1] === '' && data.row.raw[3] === '') {
                        data.cell.styles.fontStyle = 'bold';
                        data.cell.styles.fillColor = [240, 240, 240];
                        if (data.column.index === 0) {
                           data.cell.colSpan = 5;
                        }
                    }
                }
            });
        }
        doc.save(fileName);
    };

    return (
        <div className="w-full max-w-6xl mx-auto bg-white dark:bg-gray-800 rounded-lg shadow-xl overflow-hidden">
            {/* Header Section */}
            <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex flex-col sm:flex-row justify-between items-center gap-4">
                <h2 className="text-lg font-bold text-sri-blue dark:text-sri-gold">Formulario Retenciones en la Fuente</h2>
                <div className="flex items-center gap-2">
                    {monthlyData.length > 0 && (
                        <button onClick={handleClearData} className="inline-flex items-center justify-center px-4 py-2 text-sm font-medium rounded-md bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200">
                            <TrashIcon className="w-5 h-5 mr-2" /> Limpiar
                        </button>
                    )}
                    <div className="relative">
                        <label className={`inline-flex items-center justify-center px-4 py-2 text-sm font-medium rounded-md bg-sri-blue-light text-white cursor-pointer hover:bg-opacity-90 ${isProcessing ? 'opacity-50' : ''}`}>
                            {isProcessing ? <LoaderIcon className="w-5 h-5 mr-2 animate-spin" /> : <UploadIcon className="w-5 h-5 mr-2" />}
                            Llenar desde PDFs
                        </label>
                        <input type="file" className="hidden" accept="application/pdf" onChange={handleFileChange} disabled={isProcessing} multiple />
                    </div>
                    {monthlyData.length > 0 && (
                        <button onClick={handleExportPdf} className="inline-flex items-center justify-center px-4 py-2 text-sm font-medium rounded-md bg-sri-blue text-white hover:bg-opacity-90">
                            <DownloadIcon className="w-5 h-5 mr-2" /> PDF
                        </button>
                    )}
                </div>
            </div>

            {/* Metadata Inputs */}
            <div className="bg-gray-50 dark:bg-gray-900/50 p-4 border-b border-gray-200 dark:border-gray-700 grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">RUC</label>
                    <input type="text" value={ruc} onChange={(e) => setRuc(e.target.value)} className="mt-1 block w-full rounded-md border-gray-300 px-3 py-2 border dark:bg-gray-700 dark:text-white" />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Razón Social</label>
                    <input type="text" value={razonSocial} onChange={(e) => setRazonSocial(e.target.value)} className="mt-1 block w-full rounded-md border-gray-300 px-3 py-2 border dark:bg-gray-700 dark:text-white" />
                </div>
            </div>

            {error && (
                <div className="m-4 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 text-red-700 flex items-center rounded-lg">
                    <AlertTriangleIcon className="w-5 h-5 mr-3" /> {error}
                </div>
            )}

            {monthlyData.length > 0 ? (
                <>
                    {/* Month Tabs */}
                    <div className="bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-700">
                        <nav className="-mb-px flex space-x-4 px-4 overflow-x-auto">
                            {sortedMonths.map(month => (
                                <button key={month} onClick={() => setActiveMonthTab(month)} className={`${activeMonthTab === month ? 'border-sri-blue-light text-sri-blue-light' : 'border-transparent text-gray-500'} whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}>
                                    {month.substring(0,3)}
                                </button>
                            ))}
                            <button onClick={() => setActiveMonthTab('TOTAL')} className={`${activeMonthTab === 'TOTAL' ? 'border-sri-blue text-sri-blue font-bold' : 'border-transparent text-gray-500'} whitespace-nowrap py-4 px-2 border-b-2 font-medium text-sm`}>
                                TOTAL ANUAL
                            </button>
                        </nav>
                    </div>

                    {/* Level 3 Tab Title */}
                    <div className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 px-4 py-3">
                        <span className="text-sri-blue-light dark:text-sri-gold font-bold text-sm uppercase border-b-2 border-sri-blue-light dark:border-sri-gold pb-1">RET. A RESIDENTES</span>
                    </div>

                    {/* Table */}
                    <div className="p-4 overflow-x-auto">
                        <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                            <thead className="bg-gray-50 dark:bg-gray-700">
                                <tr>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase w-2/5">Descripción</th>
                                    <th className="px-4 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-300 uppercase">Cas. Base</th>
                                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 dark:text-gray-300 uppercase">Base Imponible</th>
                                    <th className="px-4 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-300 uppercase">Cas. Ret</th>
                                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 dark:text-gray-300 uppercase">Valor Retenido</th>
                                </tr>
                            </thead>
                            <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                                {withholdingStructure.map((row, index) => {
                                    if (row.isTitle) {
                                        return (
                                            <tr key={index} className="bg-gray-100 dark:bg-gray-700">
                                                <td colSpan={5} className="px-6 py-2 text-sm font-bold text-sri-blue dark:text-sri-gold uppercase">{row.description}</td>
                                            </tr>
                                        );
                                    }

                                    const valBase = row.baseField ? (dataToDisplay[row.baseField.id] || 0) : 0;
                                    const valRet = row.retentionField ? (dataToDisplay[row.retentionField.id] || 0) : 0;

                                    if (valBase === 0 && valRet === 0) return null;

                                    return (
                                        <tr key={index} className={row.isTotal ? "bg-sri-gold/20 font-bold" : "hover:bg-gray-50 dark:hover:bg-gray-700/50"}>
                                            <td className="px-6 py-4 text-sm text-gray-700 dark:text-gray-300">{row.description}</td>

                                            <td className="px-4 py-4 text-center text-xs font-mono text-gray-500">
                                                {row.baseField && <span className="px-2 py-1 rounded bg-gray-100 dark:bg-gray-600">{row.baseField.id}</span>}
                                            </td>
                                            <td className="px-6 py-4 text-right text-sm font-mono text-gray-900 dark:text-white">
                                                {valBase !== 0 ? formatNumber(valBase) : '-'}
                                            </td>

                                            <td className="px-4 py-4 text-center text-xs font-mono text-gray-500">
                                                {row.retentionField && <span className="px-2 py-1 rounded bg-gray-100 dark:bg-gray-600">{row.retentionField.id}</span>}
                                            </td>
                                            <td className="px-6 py-4 text-right text-sm font-mono text-gray-900 dark:text-white">
                                                {valRet !== 0 ? formatNumber(valRet) : '-'}
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </>
            ) : (
                <div className="text-center py-20 px-6">
                    <ClipboardListIcon className="mx-auto h-12 w-12 text-gray-400" />
                    <h3 className="mt-2 text-lg font-medium text-gray-900 dark:text-white">Formulario 103</h3>
                    <p className="mt-1 text-sm text-gray-500">Cargue sus declaraciones de retenciones (PDF) para generar el reporte.</p>
                </div>
            )}
        </div>
    );
};

